parameters.jsCode:
const item = $input.item.json;
const raw = (item.body && item.body.message && item.body.message.text) || '';
const sender = (item.body && item.body.sender) || 'unknown';

const patterns = {
  cpf: /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g,
  rg: /\b\d{1,2}\.?\d{3}\.?\d{3}-?\d{1}\b/g,
  phone: /\b\(\d{2}\)\s?9?\d{4}-?\d{4}\b/g,
  email: /\b[\w.-]+@[\w.-]+\.\w+\b/g
};
let scrubbed = raw;
let redactionCount = 0;
for (const [type, pattern] of Object.entries(patterns)) {
  const matches = scrubbed.match(pattern);
  if (matches) {
    redactionCount += matches.length;
    scrubbed = scrubbed.replace(pattern, `[${type.toUpperCase()}_REDACTED]`);
  }
}

const m = scrubbed.match(/\b(PROT[-\s]?\d{4}[-\s]?\d{4,8})\b/i);
const numeroProtocolo = m ? m[1].toUpperCase().replace(/\s/g, '-') : null;
return { json: { sender, raw, scrubbed, redactionCount, numeroProtocolo } };

